@page "/book-appointment"
@using sv_cea55ef5470d4853896f784985f00dcc.Models
@using sv_cea55ef5470d4853896f784985f00dcc.Services
@inject AppointmentService AppointmentService
@rendermode InteractiveServer

<PageTitle>Book Appointment</PageTitle>

<h3>Book an Appointment</h3>

@* ───── STEP 1: Patient Information ───── *@
<EditForm EditContext="step1Context" OnValidSubmit="HandleStep1Submit" FormName="step1">
    <DataAnnotationsValidator />

    <div class="mb-3">
        <label class="form-label">Patient Name</label>
        <InputText class="form-control" @bind-Value="patientInfo.Name" />
        <ValidationMessage For="() => patientInfo.Name" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="patientInfo.Email" />
        <ValidationMessage For="() => patientInfo.Email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Phone</label>
        <InputText class="form-control" @bind-Value="patientInfo.Phone" />
        <ValidationMessage For="() => patientInfo.Phone" />
    </div>

    <div class="mb-3">
        <label class="form-label">Insurance Provider</label>
        <InputSelect class="form-select" @bind-Value="patientInfo.InsuranceProvider">
            <option value="">-- Select --</option>
            <option value="Aetna">Aetna</option>
            <option value="BlueCross">BlueCross</option>
            <option value="Cigna">Cigna</option>
            <option value="UnitedHealth">UnitedHealth</option>
            <option value="None">None</option>
        </InputSelect>
        <ValidationMessage For="() => patientInfo.InsuranceProvider" />
    </div>

    @if (!showStep2)
    {
        <button type="submit" class="btn btn-primary">Next</button>
    }
</EditForm>

@* ───── STEP 2: Appointment Details ───── *@
@if (showStep2)
{
    <hr />
    <h4>Appointment Details</h4>

    <EditForm EditContext="step2Context" OnValidSubmit="HandleStep2Submit" FormName="step2">
        <DataAnnotationsValidator />
        <CustomValidator @ref="customValidator" />

        <div class="mb-3">
            <label class="form-label">Preferred Doctor</label>
            <InputSelect class="form-select" @bind-Value="appointmentDetail.Doctor">
                <option value="">-- Select --</option>
                @foreach (var doc in doctors)
                {
                    <option value="@doc">@doc</option>
                }
            </InputSelect>
            <ValidationMessage For="() => appointmentDetail.Doctor" />
        </div>

        <div class="mb-3">
            <label class="form-label">Date</label>
            <InputDate class="form-control" @bind-Value="appointmentDetail.Date" @bind-Value:after="OnDateChanged" />
            <ValidationMessage For="() => appointmentDetail.Date" />
        </div>

        <div class="mb-3">
            <label class="form-label">Time Slot</label>
            <InputSelect class="form-select" @bind-Value="appointmentDetail.TimeSlot">
                <option value="">-- Select --</option>
                @foreach (var slot in availableSlots)
                {
                    <option value="@slot">@slot</option>
                }
            </InputSelect>
            <ValidationMessage For="() => appointmentDetail.TimeSlot" />
        </div>

        <div class="mb-3">
            <label class="form-label">Reason for Visit</label>
            <InputTextArea class="form-control" @bind-Value="appointmentDetail.ReasonForVisit" rows="3" />
            <ValidationMessage For="() => appointmentDetail.ReasonForVisit" />
        </div>

        <button type="button" class="btn btn-secondary me-2" @onclick="GoBackToStep1">Back</button>
        <button type="submit" class="btn btn-primary" disabled="@isSubmitting">
            @(isSubmitting ? "Checking..." : "Check Availability")
        </button>
    </EditForm>
}

@if (confirmationMessage is not null)
{
    <div class="alert alert-success mt-3">@confirmationMessage</div>
}

@code {
    private PatientInfoModel patientInfo = new();
    private AppointmentDetailModel appointmentDetail = new();

    private EditContext step1Context = default!;
    private EditContext step2Context = default!;
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isSubmitting;
    private string? confirmationMessage;

    private List<string> doctors = [];
    private List<string> availableSlots = [];

    protected override async Task OnInitializedAsync()
    {
        step1Context = new EditContext(patientInfo);
        step2Context = new EditContext(appointmentDetail);
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void HandleStep1Submit()
    {
        showStep2 = true;
    }

    private async Task OnDateChanged()
    {
        if (appointmentDetail.Doctor is not null && appointmentDetail.Date.HasValue)
        {
            availableSlots = await AppointmentService.GetAvailableSlotsAsync(
                appointmentDetail.Doctor, appointmentDetail.Date.Value);
            appointmentDetail.TimeSlot = null;
        }
    }

    private async Task HandleStep2Submit()
    {
        // Validate future date manually
        if (appointmentDetail.Date.HasValue
            && appointmentDetail.Date.Value <= DateOnly.FromDateTime(DateTime.Today))
        {
            customValidator!.DisplayErrors(new Dictionary<string, List<string>>
            {
                ["Date"] = ["Date must be in the future."]
            });
            return;
        }

        isSubmitting = true;
        try
        {
            var errors = await AppointmentService.ValidatePatientAsync(
                patientInfo.Email!,
                patientInfo.InsuranceProvider!,
                appointmentDetail.Doctor!,
                appointmentDetail.TimeSlot!);

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
                return;
            }

            confirmationMessage =
                $"Appointment booked with {appointmentDetail.Doctor} on " +
                $"{appointmentDetail.Date:MMM dd, yyyy} at {appointmentDetail.TimeSlot}.";
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private void GoBackToStep1()
    {
        showStep2 = false;
        confirmationMessage = null;
    }
}

